#include <stdio.h>
#include <math.h>

// Function to perform one-sample z-test
void zTest(double sampleMean, double popMean, double stdDev, int n, double alpha) {
    // Calculate standard error
    double standardError = stdDev / sqrt(n);

    // Calculate z-statistic
    double z = (sampleMean - popMean) / standardError;

    // Critical z-value for two-tailed test at alpha
    double zCritical = 1.96;  // For alpha = 0.05

    printf("\n=== One-Sample Z-Test ===\n");
    printf("H0: Population Mean = %.2f\n", popMean);
    printf("H1: Population Mean ≠ %.2f\n", popMean);
    printf("Sample Mean: %.2f\n", sampleMean);
    printf("Sample Size: %d\n", n);
    printf("Z-Statistic: %.4f\n", z);
    printf("Critical Value: ±%.2f\n", zCritical);

    if (fabs(z) > zCritical) {
        printf("Decision: REJECT H0\n");
        printf("Conclusion: There is significant evidence that the population mean differs from %.2f\n", popMean);
    } else {
        printf("Decision: FAIL TO REJECT H0\n");
        printf("Conclusion: There is insufficient evidence to conclude the population mean differs from %.2f\n", popMean);
    }
}

int main() {
    // Example: Testing if mean weight is 70 kg
    double sampleMean = 72.5;  // Sample mean
    double popMean = 70.0;     // Hypothesized population mean
    double stdDev = 10.0;      // Population standard deviation (known)
    int n = 100;               // Sample size (large sample)
    double alpha = 0.05;       // Significance level

    zTest(sampleMean, popMean, stdDev, n, alpha);

    return 0;
}
